        for e in value:
            a.append(serialize_value(e, handles, visitor_info))
        return dict(a=a, id=id)
    if isinstance(value, dict):
        id = visitor_info.visit(value)
        o = []
        for name in value:
            o.append(
                {"k": name, "v": serialize_value(value[name], handles, visitor_info)}
            )
        return dict(o=o, id=id)
